### 6. Refactored Route Handlers (Pseudocode)

#### `src/routes/products.ts` -- After Refactoring

```typescript
import { Router } from "express";
import { getProducts, getProductById, adjustProductStock } from "../services/productService.js";
import { ServiceError } from "../services/errors.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;
  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" ? parseFloat(minPrice) : undefined,
    maxPrice: typeof maxPrice === "string" ? parseFloat(maxPrice) : undefined,
  };
  // Clean up NaN values
  if (filters.minPrice !== undefined && isNaN(filters.minPrice)) filters.minPrice = undefined;
  if (filters.maxPrice !== undefined && isNaN(filters.maxPrice)) filters.maxPrice = undefined;

  const result = getProducts(filters);
  res.json(result);
});

router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const product = getProductById(id);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: number };

    // HTTP input shape validation stays in route
    if (typeof adjustment !== "number") {
      res.status(400).json({ error: "adjustment must be a number" });
      return;
    }

    const product = adjustProductStock(id, adjustment);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as productRouter };
```

#### `src/routes/orders.ts` -- After Refactoring

