import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput } from "../types.js";
import { ValidationError } from "../errors.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export function getOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): EnrichedOrder | null {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return null;
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: CreateOrderInput): Order {
  if (input.items.length === 0) {
    throw new ValidationError("Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new ValidationError(`Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new ValidationError("Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new ValidationError(`Insufficient stock for ${product.name}`);
    }

    // Deduct stock
    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending" as const,
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(id: number, status: string): Order | null {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return null;
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    throw new ValidationError(
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`
    );
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    throw new ValidationError(
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as typeof order.status;

  return order;
}

